mapper.insert:
INSERT INTO INTEGRATED_HISTORY (
    HISTORY_ID, MEMBER_ID, ACTIVITY_TYPE, REF_ID, STATUS, CREATED_AT
) VALUES (
    SEQ_INTEGRATED_HISTORY_ID.NEXTVAL, #{memberId}, #{activityType}, #{refId}, 'P', SYSDATE
)

mapper.update:
UPDATE INTEGRATED_HISTORY
SET STATUS = #{status},
    IMAGE_URL = #{imageUrl},
    CREATED_AT = SYSDATE
WHERE MEMBER_ID = #{memberId}

  AND ACTIVITY_TYPE = #{activityType}

  AND REF_ID = #{refId}
  AND TRUNC(CREATED_AT) = TRUNC(SYSDATE)

mapper.select:
SELECT COUNT(*)
FROM INTEGRATED_HISTORY
WHERE MEMBER_ID = #{memberId}
  AND ACTIVITY_TYPE = #{activityType}
  AND STATUS = 'P'
  AND TRUNC(CREATED_AT) = TRUNC(SYSDATE)
